CREATE OR REPLACE FUNCTION what_quarter_is(date_in DATE, start_month INT) 
RETURNS INT AS $$
DECLARE
    month_num INT;
    adjusted_month INT;
BEGIN
    month_num := EXTRACT(MONTH FROM date_in);
    adjusted_month := 1 + ((month_num - start_month + 12) % 12);
    RETURN CEILING(adjusted_month / 3.0);
END;
$$ LANGUAGE plpgsql;

-- Example usage:
SELECT 
    date_in,
    what_quarter_is(date_in, 4) AS custom_quarter
FROM (
    VALUES 
        ('1995-04-01'::DATE),
        ('1995-05-15'::DATE),
        ('1995-07-23'::DATE),
        ('1995-10-10'::DATE),
        ('1996-01-05'::DATE)
) AS dates(date_in);

