CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint) 
RETURNS boolean AS $$
DECLARE
    acquired boolean;
BEGIN
    -- Try to acquire the lock without waiting
    acquired := pg_try_advisory_lock(key);

    -- If we couldn't get it immediately, try with a timeout of 1 second
    IF NOT acquired THEN
        -- Use PG_SLEEP to implement the timeout
        PERFORM pg_sleep(0.1);

        -- Try up to 10 times (total ~1 second)
        FOR i IN 1..10 LOOP
            acquired := pg_try_advisory_lock(key);
            IF acquired THEN
                RETURN true;
            END IF;
            PERFORM pg_sleep(0.1);
        END LOOP;
    END IF;

    RETURN acquired;
END;
$$ LANGUAGE plpgsql;
